# Those are .bss addresses. Let me look at .text symbols instead
DBGFILE="/tmp/debug_symbols.debug"
aarch64-linux-gnu-nm -C "$DBGFILE" 2>/dev/null | awk '
{
  if (NF >= 3 && ($2 == "T" || $2 == "t")) {
    addr = strtonum("0x" $1)
    if (addr <= 0x2f4b20 && addr > 0x2f4b20 - 0x2000) last_2f4b20 = $0
    if (addr <= 0x2f4c84 && addr > 0x2f4c84 - 0x2000) last_2f4c84 = $0
  }
}
END {
  print "Nearest to 0x2f4b20: " last_2f4b20
  print "Nearest to 0x2f4c84: " last_2f4c84
}'

